#include <stdio.h>

int main() {
    int T, N;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        if (scanf("%d", &N) != 1) break;
        if (N % 2 == 0) {
            printf("Even\n");
        } else {
            printf("Odd\n");
        }
    }
    return 0;
}

